// 获取当前时间（如果一开始没有选择测试时间，就默认为当天数据）
const now = new Date();

// 计算东八区（UTC+8）的今日开始和结束
const startOfTodayLocal = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0);
const endOfTodayLocal = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59);

// 从 Webhook 节点获取输入数据
const body = $('Webhook').item.json.body;

// 处理 retroid_id
const retroidIdsArray = items[0].json.retroid_id || [];
const retroid_id = retroidIdsArray.join(',');

// 格式化为 YYYY-MM-DDTHH:mm:ss
const formatDateToLocalString = (date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const hours = String(date.getHours()).padStart(2, '0');
  const minutes = String(date.getMinutes()).padStart(2, '0');
  const seconds = String(date.getSeconds()).padStart(2, '0');

  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}`;
};

// 设置 bgtime 和 edtime，如果为空则使用东八区的开始和结束时间
const bgtime = body.bgtime || formatDateToLocalString(startOfTodayLocal);
const edtime = body.edtime || formatDateToLocalString(endOfTodayLocal);
const procedure_name= body.procedure_name || null
// 这里将处理后的数据保存到当前节点的输出中
return [
  {
    json: {
      retroid_id,
      bgtime,
      edtime,
      procedure_name
    }
  }
];

// 获取所有输入数据
const inputData = $input.all().map(item => item.json);

// 存储统计结果
const statistics = {};

// 统计过程中记录所有 fail 的 retroid_id
let failedCountRetroids = [];

// 分组：procedure_detail_id + retroid_id
const groupedByProcedureAndRetroid = {};

inputData.forEach(record => {
  const procedure_detail_id = String(record.procedure_detail_id);
  const retroid_id = String(record.retroid_id);
  if (!groupedByProcedureAndRetroid[procedure_detail_id]) {
    groupedByProcedureAndRetroid[procedure_detail_id] = {};
  }
  if (!groupedByProcedureAndRetroid[procedure_detail_id][retroid_id]) {
    groupedByProcedureAndRetroid[procedure_detail_id][retroid_id] = [];
  }
  groupedByProcedureAndRetroid[procedure_detail_id][retroid_id].push(record);
});

const resultArray = [];

Object.entries(groupedByProcedureAndRetroid).forEach(([procedure_detail_id, retroids]) => {
  let procedure_name = '';
  let total_test_amount = 0;
  let successful_passage_count = 0;
  let failed_count = 0;
  let false_measurement_count = 0;

  Object.entries(retroids).forEach(([retroid_id, records]) => {
    // 按 created_time 升序排序
    records.sort((a, b) => new Date(a.createtime || a.created_time) - new Date(b.createtime || b.created_time));
    procedure_name = records[0].procedure_name;
    total_test_amount += 1;

    const firstResult = (records[0].result || '').toLowerCase();
    const lastResult = (records[records.length - 1].result || '').toLowerCase();

    let isFail = false;

    if (firstResult === 'pass') {
      successful_passage_count += 1;
    } else {
      if (records.length === 1) {
        failed_count += 1;
        failedCountRetroids.push(Number(retroid_id));
      } else if (records.length > 1 && lastResult === 'pass') {
        false_measurement_count += 1;
      } else {
        failed_count += 1;
        failedCountRetroids.push(Number(retroid_id));
      }
    }
  });

  const success_count = successful_passage_count + false_measurement_count;

  // 比例化
  const ratio = (count) => total_test_amount ? (count / total_test_amount * 100).toFixed(2) + '%' : '0.00%';
  const pass_rate = ratio(successful_passage_count); // 直通率
  const fail_rate = ratio(failed_count);             // 不良率
  const good_rate = ratio(success_count);            // 良率
  const false_rate = ratio(false_measurement_count); // 误测率

  resultArray.push({
    procedure_detail_id: parseInt(procedure_detail_id),
    procedure_name,
    total_test_amount,
    successful_passage_count,
    failed_count,
    false_measurement_count,
    success_count,
    pass_rate,
    fail_rate,
    good_rate,
    false_rate
  });
});

// 打印统计得到的 fail retroid_id
console.log("统计fail retroid_id:", failedCountRetroids);

return resultArray.map(stat => ({ json: stat }));

